import React from 'react';
import { Input, SearchInput } from '@linm-soft/common-components';
import { AccountSearchInput } from '../../../../../components/search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import {
  CurrencyPairField,
  useVoucherHeaderCompact,
  VoucherDescriptionField,
  VoucherFormRow,
} from '../../../../../components/voucher';
import { fieldPlaceholder } from '../../../../../components/form';
import { purchaseInvoiceFormLabels } from '../../../../../constants/purchaseInvoiceFormLabels';
import type { usePurchaseInvoiceFormController } from '../hooks/usePurchaseInvoiceFormController';

type Vm = ReturnType<typeof usePurchaseInvoiceFormController>;

export const PurchaseInvoiceHeaderSection: React.FC<{ vm: Vm }> = ({ vm }) => {
  const df = vm.styles;
  const labels = purchaseInvoiceFormLabels;
  const {
    tid,
    toolbarMode,
    isStatusLocked,
    fieldLock,
    invoiceDate,
    setInvoiceDate,
    code,
    eInvoiceNo,
    setEInvoiceNo,
    description,
    setDescription,
    currencyCode,
    currencyOptions,
    exchangeRate,
    supplierSearchConfig,
    supplierId,
    supplierCode,
    supplierName,
    setSupplierId,
    setSupplierCode,
    setSupplierName,
    creditAccountCode,
    creditAccountName,
    vatAccountCode,
    vatAccountName,
    setCreditAccountCode,
    setCreditAccountName,
    setVatAccountCode,
    setVatAccountName,
    fieldErrors,
    patchHeaderFieldError,
    headerExpanded,
    setHeaderExpanded,
  } = vm;

  const {
    isReadOnly,
    fieldLockProps,
    staticFieldProps,
    searchDisabled,
    searchViewClass,
    viewSectionClass,
  } = fieldLock;

  const searchFieldClass = [searchViewClass, df.embeddedSearch].filter(Boolean).join(' ');

  const compact = useVoucherHeaderCompact({
    enabled: true,
    headerExpanded,
    styles: {
      field: df.field,
      headerCompactHidden: df.headerCompactHidden,
      headerCompactActive: df.headerCompactActive,
    },
  });
  const formRowStyles = { row4: df.row4 };

  const headerToggle = (
    <button
      type="button"
      className={df.headerToggleBtn}
      data-testid={tid(headerExpanded ? 'header-collapse' : 'header-expand')}
      aria-expanded={headerExpanded}
      onClick={() => setHeaderExpanded(v => !v)}
    >
      <span className={df.headerToggleIcon} aria-hidden>
        <i className={headerExpanded ? 'fas fa-chevron-up' : 'fas fa-chevron-down'} />
      </span>
      {headerExpanded ? labels.headerCollapse : labels.headerExpand}
    </button>
  );

  const sectionClass = [df.section, viewSectionClass, compact.headerCompactSectionClass]
    .filter(Boolean)
    .join(' ');

  return (
    <div className={sectionClass} data-testid={tid('section-header')}>
      <div className={df.sectionTitleRow}>
        <h2 className={df.sectionTitle}>{labels.sectionHeader}</h2>
        {headerToggle}
      </div>

      <div className={df.headerFieldsFlow}>
        <VoucherFormRow styles={formRowStyles}>
          <div
            className={compact.fieldClass(compact.compactHideClass(true))}
            id={tid('field-invoiceDate')}
            data-testid={tid('field-invoiceDate')}
          >
            <label className={df.label}>Ngày HĐ *</label>
            <Input
              type="date"
              value={invoiceDate}
              error={fieldErrors.invoiceDate}
              onChange={e => {
                setInvoiceDate(e.target.value);
                patchHeaderFieldError('invoiceDate', e.target.value);
              }}
              {...fieldLockProps}
            />
          </div>
          <div className={compact.fieldClass(compact.compactHideClass(false))} data-testid={tid('field-code')}>
            <label className={df.label}>Số chứng từ</label>
            <Input
              value={code}
              {...staticFieldProps}
              placeholder={fieldPlaceholder(toolbarMode, 'Tự động sinh', { isStatusLocked })}
            />
          </div>
          <div className={compact.fieldClass(compact.compactHideClass(false))} data-testid={tid('field-eInvoiceNo')}>
            <label className={df.label}>Số HĐ điện tử</label>
            <Input value={eInvoiceNo} onChange={e => setEInvoiceNo(e.target.value)} {...fieldLockProps} />
          </div>
          <CurrencyPairField
            className={compact.fieldClass(compact.compactHideClass(false))}
            currencyCode={currencyCode}
            exchangeRate={exchangeRate}
            currencyOptions={currencyOptions}
            staticFieldProps={staticFieldProps}
            selectDisabled={searchDisabled}
            testId={tid}
          />
        </VoucherFormRow>
        <VoucherFormRow styles={formRowStyles}>
          <div
            className={`${df.spanCol2} ${compact.fieldClass(compact.compactHideClass(true))}`}
            id={tid('field-supplierId')}
            data-testid={tid('field-supplierId')}
          >
            <label className={df.label}>Nhà cung cấp *</label>
            <SearchInput
              config={supplierSearchConfig}
              value={supplierId}
              primaryDisplay={supplierCode}
              secondaryDisplay={supplierName}
              onChange={c => {
                setSupplierId(c.customerId);
                setSupplierCode(c.code);
                setSupplierName(c.name);
                patchHeaderFieldError('supplierId', c.customerId);
              }}
              onClear={() => {
                setSupplierId('');
                setSupplierCode('');
                setSupplierName('');
                patchHeaderFieldError('supplierId', '');
              }}
              className={searchFieldClass}
              showLabel={false}
              error={fieldErrors.supplierId}
              disabled={searchDisabled}
            />
          </div>
          <div
            className={compact.fieldClass(compact.compactHideClass(true))}
            id={tid('field-creditAccountCode')}
            data-testid={tid('field-creditAccountCode')}
          >
            <label className={df.label}>TK Có (công nợ) *</label>
            <AccountSearchInput
              api={erpFinanceAccountSearchApi}
              value={creditAccountCode}
              primaryDisplay={formatAccountDisplay(creditAccountCode, creditAccountName)}
              secondaryDisplay={creditAccountName}
              onChange={a => {
                setCreditAccountCode(a.code);
                setCreditAccountName(a.name);
                patchHeaderFieldError('creditAccountCode', a.code);
              }}
              onClear={() => {
                setCreditAccountCode('');
                setCreditAccountName('');
                patchHeaderFieldError('creditAccountCode', '');
              }}
              showLabel={false}
              showSecondaryInput={false}
              error={fieldErrors.creditAccountCode}
              className={searchFieldClass}
              disabled={searchDisabled}
              placeholder="331..."
            />
          </div>
          <div
            className={compact.fieldClass(compact.compactHideClass(true))}
            id={tid('field-vatAccountCode')}
            data-testid={tid('field-vatAccountCode')}
          >
            <label className={df.label}>TK thuế GTGT *</label>
            <AccountSearchInput
              api={erpFinanceAccountSearchApi}
              value={vatAccountCode}
              primaryDisplay={formatAccountDisplay(vatAccountCode, vatAccountName)}
              secondaryDisplay={vatAccountName}
              onChange={a => {
                setVatAccountCode(a.code);
                setVatAccountName(a.name);
                patchHeaderFieldError('vatAccountCode', a.code);
              }}
              onClear={() => {
                setVatAccountCode('');
                setVatAccountName('');
                patchHeaderFieldError('vatAccountCode', '');
              }}
              showLabel={false}
              showSecondaryInput={false}
              error={fieldErrors.vatAccountCode}
              className={searchFieldClass}
              disabled={searchDisabled}
              placeholder="1331..."
            />
          </div>
        </VoucherFormRow>
        <VoucherFormRow styles={formRowStyles}>
          <div
            className={`${df.spanCol4} ${compact.fieldClass(compact.compactHideClass(false))}`}
            id={tid('field-description')}
            data-testid={tid('field-description')}
          >
            <label className={df.label}>{labels.description}</label>
            <VoucherDescriptionField
              value={description}
              error={fieldErrors.description}
              onChange={v => {
                setDescription(v);
                patchHeaderFieldError('description', v);
              }}
              readOnly={isReadOnly}
              disabled={isReadOnly}
            />
          </div>
        </VoucherFormRow>
      </div>
    </div>
  );
};
